(()=>{var t=document.getElementById("menu-toggle");null!==t&&t.addEventListener("click",function(e){0<=document.body.className.indexOf("menu-open")?(document.body.className=document.body.className.replace(/\s*menu-open\s*/g," ").trim(),t.setAttribute("aria-expanded","false")):(document.body.className=(document.body.className+" menu-open").trim(),t.setAttribute("aria-expanded","true")),e.preventDefault(),e.stopPropagation()})})();